import{_ as r,r as t,o as c,c as l,a as n,b as e,d as s,w as d,e as o}from"./app-25fa875f.js";const p="/blog/assets/git-proxy-5e7a1588.png",u={},h=n("h1",{id:"git-proxy",tabindex:"-1"},[n("a",{class:"header-anchor",href:"#git-proxy","aria-hidden":"true"},"#"),e(" Git - Proxy")],-1),m=n("p",null,"Created by : Mr Dk.",-1),v=n("p",null,"2020 / 02 / 19 13:28",-1),b=n("p",null,"Ningbo, Zhejiang, China",-1),g=n("hr",null,null,-1),_=n("code",null,"clone",-1),k=n("code",null,"fetch",-1),x=n("code",null,"pull",-1),f=n("code",null,"push",-1),y=o(`<p>GitHub 有 HTTPS 和 SSH 两种访问方式。在我自己的电脑上，由于我有自己的 RSA 公私钥，所以一般使用 SSH 方式。对这两种访问方式，设置代理的方式也有所不同。</p><h2 id="https-proxy" tabindex="-1"><a class="header-anchor" href="#https-proxy" aria-hidden="true">#</a> HTTPS Proxy</h2><p>这种网上的解决方式是最多的，直接在 Git 命令行中设置即可。</p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token function">git</span> config –global http.proxy http://<span class="token punctuation">[</span>user:password@<span class="token punctuation">]</span><span class="token number">10.167</span>.32.133:8080
<span class="token function">git</span> config –global http.proxy https://<span class="token punctuation">[</span>user:password@<span class="token punctuation">]</span><span class="token number">10.167</span>.32.133:8080
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div></div></div><p>如果使用本地代理，那么使用 <code>127.0.0.1</code>。</p><p>相应的撤销代理方法：</p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token function">git</span> config <span class="token parameter variable">--global</span> <span class="token parameter variable">--unset</span> http.proxy
<span class="token function">git</span> config <span class="token parameter variable">--global</span> <span class="token parameter variable">--unset</span> https.proxy
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div></div></div><h2 id="ssh-proxy" tabindex="-1"><a class="header-anchor" href="#ssh-proxy" aria-hidden="true">#</a> SSH Proxy</h2><h3 id="windows" tabindex="-1"><a class="header-anchor" href="#windows" aria-hidden="true">#</a> Windows</h3>`,9),S={href:"https://communary.net/2017/01/12/getting-git-to-work-through-a-proxy-server-in-windows/",target:"_blank",rel:"noopener noreferrer"},w={href:"https://gitforwindows.org/",target:"_blank",rel:"noopener noreferrer"},P=n("em",null,"Git for Windows",-1),H={href:"https://github.com/2dust/v2rayN",target:"_blank",rel:"noopener noreferrer"},G=n("em",null,"V2Ray",-1),C=o(`<p>具体的设置方式是在 SSH 的配置文件 (<code>~/.ssh/config</code>) 中添加规则。规则中的代理命令需要使用到一个叫做 <code>connect.exe</code> 的程序。这个程序不用另外下载，在 Git for Windows 的安装目录下已经提供：<code>&lt;Git_Path&gt;/Git/mingw64/bin/</code>。该程序的使用方式如下：</p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code>$ connect
connect --- simple relaying <span class="token builtin class-name">command</span> via proxy.
Version <span class="token number">1.105</span>
usage: C:<span class="token punctuation">\\</span>Program Files<span class="token punctuation">\\</span>Git<span class="token punctuation">\\</span>mingw64<span class="token punctuation">\\</span>bin<span class="token punctuation">\\</span>connect.exe <span class="token punctuation">[</span>-dnhst45<span class="token punctuation">]</span> <span class="token punctuation">[</span>-p local-port<span class="token punctuation">]</span>
          <span class="token punctuation">[</span>-H proxy-server<span class="token punctuation">[</span>:port<span class="token punctuation">]</span><span class="token punctuation">]</span> <span class="token punctuation">[</span>-S <span class="token punctuation">[</span>user@<span class="token punctuation">]</span>socks-server<span class="token punctuation">[</span>:port<span class="token punctuation">]</span><span class="token punctuation">]</span>
          <span class="token punctuation">[</span>-T proxy-server<span class="token punctuation">[</span>:port<span class="token punctuation">]</span><span class="token punctuation">]</span>
          <span class="token punctuation">[</span>-c telnet-proxy-command<span class="token punctuation">]</span>
          <span class="token function">host</span> port
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>根据该程序的使用方法，可以使用 <code>-H</code> 参数下的 HTTP 代理和 <code>-S</code> 参数下的 SOCKS 代理 (其它代理反正我也没有不就深究含义)。我这边的 V2Ray 支持 HTTP 和 SOCKS 两种代理，只是端口号不一样，所以我就使用了 SOCKS 代理。在本地 SSH 的配置文件中添加如下规则：</p><div class="language-ssh line-numbers-mode" data-ext="ssh"><pre class="language-ssh"><code>Host github.com
    ProxyCommand &quot;C:\\Program Files\\Git\\mingw64\\bin\\connect.exe&quot; -S 127.0.0.1:10808 %h %p
    IdentityFile &quot;~/.ssh/id_rsa&quot;
    TCPKeepAlive yes
    IdentitiesOnly yes
    User git
    Port 22
    Hostname github.com
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>添加好规则之后，之后再通过 SSH 访问 GitHub 时，就会通过代理访问，速度大大加快：</p><p><img src="`+p+`" alt="git-proxy"></p><p>如果不使用 SOCKS 代理，使用 HTTP 代理也是可以的，把参数协议和 IP 地址、端口号换一下应该就可以了，就不折腾了。算是解决了因为网络带来的一些烦恼。</p><h3 id="linux" tabindex="-1"><a class="header-anchor" href="#linux" aria-hidden="true">#</a> Linux</h3><p>Linux 下主要是 <code>ProxyCommand</code> 的不同。如果正在使用 WSL，并且代理服务搭建在 Windows 上的话，<code>ProxyCommand</code> 中需要填写 <code>/etc/resolv.conf</code> 中的 <code>nameserver</code> IP 地址（也就是 Windows 的局域网地址）。</p><div class="language-ssh line-numbers-mode" data-ext="ssh"><pre class="language-ssh"><code>Host github.com
    ProxyCommand nc -v -x 127.0.0.1:10808 %h %p
    IdentityFile &quot;~/.ssh/id_rsa&quot;
    TCPKeepAlive yes
    IdentitiesOnly yes
    User git
    Port 22
    Hostname github.com
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><hr><h2 id="references" tabindex="-1"><a class="header-anchor" href="#references" aria-hidden="true">#</a> References</h2>`,12),T={href:"https://communary.net/2017/01/12/getting-git-to-work-through-a-proxy-server-in-windows/",target:"_blank",rel:"noopener noreferrer"},I={href:"https://gist.github.com/coin8086/7228b177221f6db913933021ac33bb92",target:"_blank",rel:"noopener noreferrer"};function N(L,V){const i=t("RouterLink"),a=t("ExternalLinkIcon");return c(),l("div",null,[h,m,v,b,g,n("p",null,[e("受限于国内的网络环境，用 Git 从 GitHub 上 "),_,e(" / "),k,e(" / "),x,e(" / "),f,e(" 都痛苦异常。这段时间放假在家，家里的网速比实验室里的还慢，用 "),s(i,{to:"/notes/Network/Network%20GitHub%20Accelerating.html"},{default:d(()=>[e("配置 GitHub DNS")]),_:1}),e(" 的方法已经不太奏效了。就算 IP 地址没有被污染，从国内连到国外相应服务器的延迟依旧很高。因此，试图配置 Git 的代理，借由在境外租用的服务器，来加速 Git 对 GitHub 的访问。")]),y,n("p",null,[e("在 Baidu 上没有找到解决方案，后来通过 Google 看了一篇 "),n("a",S,[e("博客"),s(a)]),e(" 发现符合我的应用场景，并且经过测试方法是有效的。我的应用场景是 "),n("a",w,[P,s(a)]),e(" + "),n("a",H,[G,s(a)]),e(" 的本地代理。")]),C,n("p",null,[n("a",T,[e("Getting git to work through a proxy server (in Windows)"),s(a)])]),n("p",null,[n("a",I,[e("Use Proxy for Git/GitHub"),s(a)])])])}const q=r(u,[["render",N],["__file","Git Proxy.html.vue"]]);export{q as default};
